const toStringSafe = (value) => {
  if (value === null || value === undefined) return '';
  if (typeof value === 'string') return value;
  if (typeof value === 'object' && typeof value.toString === 'function') return value.toString();
  return String(value);
};

const toIsoSafe = (value) => {
  if (!value) return null;
  if (typeof value === 'string') return value;
  if (value instanceof Date) return value.toISOString();
  if (typeof value.toISOString === 'function') return value.toISOString();
  return String(value);
};

const items = $input.all();
return items.map((item) => ({
  json: {
    _id: toStringSafe(item.json._id),
    user_id: item.json.user_id || '',
    active_image_url: item.json.active_image_url || '',
    image_activated_at: toIsoSafe(item.json.image_activated_at),
    username: toStringSafe(item.json.username || item.json.name || '').trim(),
  },
}));

const userId = $input.first().json.query?.userId || '';
const mongoQuery = userId ? { sessionId: userId } : {};

return [
  {
    json: {
      requestedUserId: userId || null,
      mongoQueryString: JSON.stringify(mongoQuery),
    },
  },
];

const toStringSafe = (value) => {
  if (value === null || value === undefined) return '';
  if (typeof value === 'string') return value;
  if (typeof value === 'number' || typeof value === 'boolean') return String(value);
  try {
    return JSON.stringify(value);
  } catch {
    return String(value);
  }
};

const pad2 = (value) => String(value).padStart(2, '0');

const parseDate = (raw) => {
  if (!raw || typeof raw !== 'string') return null;

  if (/^\d{4}-\d{2}-\d{2}/.test(raw)) {
    return raw.slice(0, 10);
  }

  const parts = raw.split('/').map((part) => Number(part.trim()));
  if (parts.length !== 3 || parts.some((part) => Number.isNaN(part))) {
    return null;
  }

  const [day, month, yearRaw] = parts;
  const year = yearRaw < 100 ? 2000 + yearRaw : yearRaw;
  return `${year}-${pad2(month)}-${pad2(day)}`;
};

const parseTime = (raw) => {
  if (!raw || typeof raw !== 'string') return null;

  const parts = raw.split(':').map((part) => Number(part.trim()));
  if (parts.length < 2 || parts.length > 3 || parts.some((part) => Number.isNaN(part))) {
    return null;
  }

  const [hour, minute, second = 0] = parts;
  if (
    hour < 0 ||
    hour > 23 ||
    minute < 0 ||
    minute > 59 ||
    second < 0 ||
    second > 59
  ) {
    return null;
  }

  return `${pad2(hour)}:${pad2(minute)}:${pad2(second)}`;
};

const buildDatetime = (message) => {
  if (message?.datetime && typeof message.datetime === 'string') {
    const rawDatetime = message.datetime.trim();
    if (!Number.isNaN(new Date(rawDatetime).getTime())) {
      return rawDatetime;
    }
  }

  const metadata = message?.data?.response_metadata || {};
  const isHuman = message?.type === 'human';
  const dateRaw =
    (isHuman ? metadata.human_date : metadata.ai_date) || metadata.date || metadata.message_date;
  const timeRaw =
    (isHuman ? metadata.human_time : metadata.ai_time) || metadata.time || metadata.message_time;

  const isoDate = parseDate(dateRaw);
  const isoTime = parseTime(timeRaw);
  if (!isoDate || !isoTime) {
    return null;
  }

  return `${isoDate}T${isoTime}`;
};

const getStrictHumanTurnContext = (message) => {
  const executionId = toStringSafe(
    message?.execution_id || message?.data?.response_metadata?.executionID
  ).trim();

  const metadata = message?.data?.response_metadata || {};
  const isoDate = parseDate(metadata.human_date);
  const isoTime = parseTime(metadata.human_time);

  if (!executionId || !isoDate || !isoTime) {
    return null;
  }

  return {
    executionId,
    datetime: `${isoDate}T${isoTime}`,
  };
};

const normalizeToolCall = (toolCall) => {
  if (!toolCall || typeof toolCall !== 'object') {
    return null;
  }

  const id = toStringSafe(toolCall.id || toolCall?.args?.id).trim();
  const name = toStringSafe(toolCall.name).trim();
  const args =
    toolCall.args && typeof toolCall.args === 'object' && !Array.isArray(toolCall.args)
      ? toolCall.args
      : {};

  if (!id && !name) {
    return null;
  }

  return {
    id,
    name,
    args,
  };
};

const extractToolCalls = (message) => {
  const candidates = [
    message?.data?.tool_calls,
    message?.tool_calls,
    message?.data?.additional_kwargs?.tool_calls,
    message?.additional_kwargs?.tool_calls,
  ];

  const rawToolCalls =
    candidates.find((candidate) => Array.isArray(candidate) && candidate.length) || [];

  return rawToolCalls
    .map((toolCall) => normalizeToolCall(toolCall))
    .filter((toolCall) => Boolean(toolCall));
};

const normalizeToolResponse = (message) => ({
  tool_call_id: toStringSafe(message?.data?.tool_call_id || message?.tool_call_id).trim(),
  name: toStringSafe(message?.data?.name || message?.name).trim(),
  content: toStringSafe(message?.data?.content || message?.content),
});

const parseJsonIfPossible = (content) => {
  const text = toStringSafe(content).trim();
  if (!text.startsWith('{') && !text.startsWith('[')) {
    return null;
  }

  try {
    return JSON.parse(text);
  } catch {
    return null;
  }
};

const hasErrorSignalInText = (text) =>
  /there was an error|workflow did not return a response|invalid url|failed|exception|technical issue/i.test(
    text
  );

const hasErrorSignalInParsedValue = (value) => {
  if (Array.isArray(value)) {
    return value.some((item) => hasErrorSignalInParsedValue(item));
  }

  if (!value || typeof value !== 'object') {
    return false;
  }

  const status = typeof value.status === 'string' ? value.status.toLowerCase() : '';
  if (status === 'error' || status === 'failed') {
    return true;
  }

  if (value.error_code !== null && value.error_code !== undefined && value.error_code !== '') {
    return true;
  }

  if (typeof value.error_message === 'string' && value.error_message.trim()) {
    return true;
  }

  if (typeof value.response === 'string' && hasErrorSignalInText(value.response)) {
    return true;
  }

  if (typeof value.text === 'string' && hasErrorSignalInText(value.text)) {
    return true;
  }

  return Object.values(value).some((item) => hasErrorSignalInParsedValue(item));
};

const detectToolError = (content) => {
  const parsed = parseJsonIfPossible(content);
  if (parsed !== null) {
    return hasErrorSignalInParsedValue(parsed);
  }

  return hasErrorSignalInText(toStringSafe(content));
};

const buildToolResponseLookup = (rawMessages) => {
  const toolResponsesById = new Map();

  rawMessages.forEach((message) => {
    if (message?.type !== 'tool') {
      return;
    }

    const response = normalizeToolResponse(message);
    if (!response.tool_call_id || toolResponsesById.has(response.tool_call_id)) {
      return;
    }

    toolResponsesById.set(response.tool_call_id, response);
  });

  return toolResponsesById;
};

const items = $input.all();
return items.map((item) => {
  const rawMessages = Array.isArray(item.json.messages) ? item.json.messages : [];
  const toolResponsesById = buildToolResponseLookup(rawMessages);

  const messages = [];
  let hasStartedWithValidHuman = false;
  let activeTurnDatetime = null;

  rawMessages.forEach((message, index) => {
    if (message?.type === 'human') {
      const strictHumanTurn = getStrictHumanTurnContext(message);
      if (!strictHumanTurn) {
        return;
      }

      hasStartedWithValidHuman = true;
      activeTurnDatetime = strictHumanTurn.datetime;

      const humanMediaUrls = Array.isArray(message?.data?.additional_kwargs?.mediaUrls)
        ? message.data.additional_kwargs.mediaUrls.filter((url) => typeof url === 'string' && url.trim())
        : [];

      messages.push({
        order: index,
        type: 'human',
        data: {
          content: toStringSafe(message?.data?.content || message?.content),
          media_urls: humanMediaUrls,
        },
        datetime: strictHumanTurn.datetime,
        execution_id: strictHumanTurn.executionId,
      });

      return;
    }

    if (!hasStartedWithValidHuman) {
      return;
    }

    if (message?.type !== 'ai') {
      return;
    }

    const datetime = buildDatetime(message) || activeTurnDatetime;
    if (!datetime) {
      return;
    }

    const toolCalls = extractToolCalls(message);
    if (!toolCalls.length) {
      const aiMediaUrls = Array.isArray(message?.data?.additional_kwargs?.mediaUrls)
        ? message.data.additional_kwargs.mediaUrls.filter((url) => typeof url === 'string' && url.trim())
        : [];

      messages.push({
        order: index,
        type: 'ai',
        data: {
          content: toStringSafe(message?.data?.content || message?.content),
          media_urls: aiMediaUrls,
        },
        datetime,
        execution_id: null,
      });
      return;
    }

    toolCalls.forEach((toolCall) => {
      const matchedToolResponse = toolCall.id ? toolResponsesById.get(toolCall.id) : null;

      const toolResponse = {
        tool_call_id: toStringSafe(matchedToolResponse?.tool_call_id || toolCall.id).trim(),
        name: toStringSafe(matchedToolResponse?.name || toolCall.name).trim(),
        content: toStringSafe(matchedToolResponse?.content),
      };

      messages.push({
        order: index,
        type: 'tool',
        data: {
          tool_call: toolCall,
          tool_response: toolResponse,
          is_error: detectToolError(toolResponse.content),
        },
        datetime,
        execution_id: null,
      });
    });
  });

  const orderedMessages = messages
    .sort((a, b) => {
      const timeDelta = new Date(a.datetime).getTime() - new Date(b.datetime).getTime();
      if (timeDelta !== 0) {
        return timeDelta;
      }
      return a.order - b.order;
    })
    .map(({ order, ...message }) => message);

  return {
    json: {
      _id: toStringSafe(item.json._id),
      sessionId: item.json.sessionId || '',
      messages: orderedMessages,
    },
  };
});

