const buildMessageDatetime = (message) => {
  if (message?.datetime && typeof message.datetime === 'string') {
    const rawDatetime = message.datetime.trim();
    if (!Number.isNaN(new Date(rawDatetime).getTime())) {
      return rawDatetime;
    }
  }

  const metadata = message?.data?.response_metadata || {};
  const isHuman = message?.type === 'human';
  const dateField =
    (isHuman ? metadata.human_date : metadata.ai_date) || metadata.date || metadata.message_date;
  const timeField =
    (isHuman ? metadata.human_time : metadata.ai_time) || metadata.time || metadata.message_time;

  const isoDate = parseDateString(dateField);
  const isoTime = parseTimeString(timeField);
  if (!isoDate || !isoTime) {
    return null;
  }

  return `${isoDate}T${isoTime}`;
};

const isPreviewType = (value) => value === 'human' || value === 'ai' || value === 'tool';

const normalizePreviewMessage = (message) => {
  if (!message || typeof message !== 'object') {
    return null;
  }

  const rawType = typeof message?.type === 'string' ? message.type.trim().toLowerCase() : '';
  const type = isPreviewType(rawType) ? rawType : 'ai';

  const datetime = buildMessageDatetime(message);
  if (!datetime) {
    return null;
  }

  const content =
    type === 'tool'
      ? toStringSafe(
          message?.data?.tool_response?.content || message?.data?.content || message?.content
        )
      : toStringSafe(message?.data?.content || message?.content);

  return {
    type,
    content,
    datetime,
  };
};

const latestBySession = {};

const applyCandidate = (sessionId, candidate) => {
  if (!candidate) return;
  const existing = latestBySession[sessionId];
  if (!existing || new Date(candidate.datetime).getTime() > new Date(existing.datetime).getTime()) {
    latestBySession[sessionId] = candidate;
  }
};

for (const item of $input.all()) {
  const chat = item.json || {};
  const sessionId = toStringSafe(chat.sessionId || chat.user_id || chat.session_id).trim();
  if (!sessionId) {
    continue;
  }

  applyCandidate(sessionId, normalizePreviewMessage(chat.lastMessage));

  const rawMessages = Array.isArray(chat.messages) ? chat.messages : [];
  for (const message of rawMessages) {
    applyCandidate(sessionId, normalizePreviewMessage(message));
  }
}

return [
  {
    json: {
      latestBySession,
    },
  },
];

