  if (!value) return null;
  if (typeof value === 'string') return value;
  if (value instanceof Date) return value.toISOString();
  if (typeof value.toISOString === 'function') return value.toISOString();
  return String(value);
};

const latestBySession =
  $items('Collect Latest By Session For Preview', 0, 0)?.[0]?.json?.latestBySession || {};

return $input.all().map((item) => {
  const userId = item.json.user_id || '';

  return {
    json: {
      _id: toStringSafe(item.json._id),
      user_id: userId,
      active_image_url: item.json.active_image_url || item.json.active_image_id || '',
      image_activated_at: toIsoSafe(item.json.image_activated_at),
      username: toStringSafe(item.json.username || item.json.name || '').trim(),
      latest_message: latestBySession[userId] || null,
    },
  };
});

const chats = $('Mongo Chats For Insights').all().map(i => i.json);

const seenUserIds = new Set();
const users = $('Mongo Users For Insights').all()
  .map(i => i.json)
  .filter(u => {
    const uid = String(u._id || u.user_id || '');
    if (!uid || seenUserIds.has(uid)) return false;
    seenUserIds.add(uid);
    return true;
  });

let totalMessages = 0;
let humanCount = 0, aiCount = 0, toolCount = 0, toolErrors = 0;
const messagesByDate = {};
const toolUsage = {};
const userMessageCounts = {};
const activityByHour = Array(24).fill(0);
const activityByDateHour = {};

for (const chat of chats) {
  const msgs = chat.messages || [];
  const sid = chat.sessionId;
  userMessageCounts[sid] = (userMessageCounts[sid] || 0) + msgs.length;

  for (const msg of msgs) {
    totalMessages++;
    const type = msg.type || (msg.kwargs?.type);
    const dt = msg.datetime || msg.response_metadata?.human_date;

    if (type === 'human') humanCount++;
    else if (type === 'ai') aiCount++;
    else if (type === 'tool') {
      toolCount++;
      if (msg.data?.is_error || msg.is_error) toolErrors++;
    }

    if (dt) {
      const dateKey = String(dt).slice(0, 10);
      if (!messagesByDate[dateKey]) messagesByDate[dateKey] = { human: 0, ai: 0, tool: 0 };
      messagesByDate[dateKey][type] = (messagesByDate[dateKey][type] || 0) + 1;

      const timeStr = msg.datetime ? String(dt).slice(11, 13) : (msg.response_metadata?.human_time || '').slice(0, 2);
      const hour = parseInt(timeStr, 10);
      if (!isNaN(hour) && hour >= 0 && hour < 24) {
        activityByHour[hour]++;
        const bucketKey = dateKey + '|' + hour;
        if (!activityByDateHour[bucketKey]) activityByDateHour[bucketKey] = { date: dateKey, hour, count: 0 };
        activityByDateHour[bucketKey].count++;
      }
    }

    const toolName = msg.data?.tool_call?.name || msg.name;
    if (toolName) {
      if (!toolUsage[toolName]) toolUsage[toolName] = { calls: 0, errors: 0 };
      toolUsage[toolName].calls++;
      if (msg.data?.is_error || msg.is_error) toolUsage[toolName].errors++;
    }
  }
}

const totalUsers = users.length;
const activeSessions = chats.filter(c => (c.messages || []).length > 0).length;
const _generateImageTool = toolUsage['generate_image'] || {};
const imagesGenerated = (_generateImageTool.calls || 0) - (_generateImageTool.errors || 0);
const avgMessagesPerUser = totalUsers > 0 ? Math.round(totalMessages / totalUsers) : 0;
const toolErrorRate = toolCount > 0 ? Math.round((toolErrors / toolCount) * 100) : 0;

const topUsers = Object.entries(userMessageCounts)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 10)
  .map(([sessionId, count]) => {
    const user = users.find(u => u.user_id === sessionId || u._id === sessionId);
    return { sessionId, messageCount: count, username: user?.username || null };
  });

return [{
  json: {
    overview: { totalUsers, totalMessages, activeSessions, imagesGenerated, avgMessagesPerUser, toolErrorRate },
    messagesByDate: Object.entries(messagesByDate)
      .sort((a, b) => a[0].localeCompare(b[0]))
      .map(([date, counts]) => ({ date, ...counts, total: (counts.human||0)+(counts.ai||0)+(counts.tool||0) })),
    messageTypeBreakdown: { human: humanCount, ai: aiCount, tool: toolCount },
    toolUsage: Object.entries(toolUsage)
      .sort((a, b) => b[1].calls - a[1].calls)
      .map(([name, d]) => ({ name, calls: d.calls, errors: d.errors, successRate: Math.round(((d.calls - d.errors) / d.calls) * 100) })),
    topUsers,
    activityByHour: activityByHour.map((count, hour) => ({ hour, count })),
    activityByDateHour: Object.values(activityByDateHour)
      .sort((a, b) => {
        if (a.date !== b.date) return a.date.localeCompare(b.date);
        return a.hour - b.hour;
      })
  }
}];

const query = $input.first().json.query || {};
const chatUserIdsRaw = typeof query.chatUserIds === 'string' ? query.chatUserIds.trim() : '';
const singleChatUserId = typeof query.chatUserId === 'string' ? query.chatUserId.trim() : '';

let mongoQuery = {};

if (chatUserIdsRaw) {
  const ids = chatUserIdsRaw
    .split(',')
    .map((s) => s.trim())
    .filter(Boolean);

  mongoQuery = ids.length ? { chatUserId: { $in: ids } } : { chatUserId: '__none__' };
} else if (singleChatUserId) {
  mongoQuery = { chatUserId: singleChatUserId };
}

return [{
  json: {
    mongoQueryString: JSON.stringify(mongoQuery),
  },
}];

const toStringSafe = (value) => {
  if (value === null || value === undefined) return '';
  if (typeof value === 'string') return value;
  if (value instanceof Date) return value.toISOString();
  if (typeof value === 'object' && typeof value.toString === 'function') return value.toString();
  return String(value);
};

const toIsoSafe = (value) => {
  if (!value) return null;
  const parsed = new Date(value).getTime();
  if (!Number.isNaN(parsed)) return new Date(parsed).toISOString();
  return toStringSafe(value);
};

return $input.all().map((item) => ({
  json: {
    chatUserId: toStringSafe(item.json.chatUserId).trim(),
    reviewerName: toStringSafe(item.json.reviewerName).trim().toLowerCase(),
    lastReadDatetime: toIsoSafe(item.json.lastReadDatetime),
    markedAt: toIsoSafe(item.json.markedAt),
  },
}));

const body = $input.first().json.body || {};

const chatUserId = String(body.chatUserId || '').trim();
const reviewerName = String(body.reviewerName || '').trim().toLowerCase();
const lastReadDatetime = String(body.lastReadDatetime || '').trim();
const markedAt = String(body.markedAt || '').trim() || new Date().toISOString();

if (!chatUserId || !reviewerName || !lastReadDatetime) {
  throw new Error('chatUserId, reviewerName, and lastReadDatetime are required');
}

const id = `${chatUserId}::${reviewerName}`;

return [{
  json: {
    id,
    chatUserId,
    reviewerName,
    lastReadDatetime,
    markedAt,
  },
}];
